import L from 'leaflet';
import React, { useEffect, useState } from "react";
import { MapContainer, TileLayer, Marker, Popup, Tooltip, Polyline, useMap } from "react-leaflet";
import "leaflet/dist/leaflet.css";
import axios from "axios";

// --- Helper function to calculate bearing ---
function calculateBearing(lat1, lon1, lat2, lon2) {
    const dLon = (lon2 - lon1);
    const y = Math.sin(dLon) * Math.cos(lat2);
    const x = Math.cos(lat1) * Math.sin(lat2) - Math.sin(lat1) * Math.cos(lat2) * Math.cos(dLon);
    let brng = Math.atan2(y, x);
    brng = (brng * 180 / Math.PI + 360) % 360;
    return brng;
}

// --- Bus Icon Component ---
const BusIcon = ({ status, bearing }) => {
    const iconHtml = `<div style="transform: rotate(${bearing}deg); font-size: 24px;">🚌</div>`;
    const color = status === "Ghost" ? "red" : "green";
    
    return L.divIcon({
        html: `<div style="background-color: ${color}; border-radius: 50%; width: 30px; height: 30px; display: flex; align-items: center; justify-content: center;">${iconHtml}</div>`,
        className: 'custom-bus-icon',
        iconSize: [30, 30],
        iconAnchor: [15, 15]
    });
};

// --- Bus Information Panel ---
const BusInfoPanel = ({ bus, onClose }) => {
    if (!bus) return null;
    return (
        <div style={{
            position: 'absolute',
            top: '10px',
            right: '10px',
            width: '250px',
            background: 'white',
            padding: '10px',
            borderRadius: '5px',
            zIndex: 1000,
            boxShadow: '0 1px 5px rgba(0,0,0,0.4)'
        }}>
            <button onClick={onClose} style={{ float: 'right' }}>X</button>
            <h3>Bus Details</h3>
            <p><b>Bus ID:</b> {bus.id}</p>
            <p><b>Route:</b> {bus.route}</p>
            <p><b>Status:</b> {bus.status}</p>
            <p><b>Speed:</b> {bus.speed.toFixed(1)} km/h</p>
        </div>
    );
};

export default function BusMap() {
    const [buses, setBuses] = useState([]);
    const [counts, setCounts] = useState({ running_count: 0, ghost_count: 0 });
    const [positions, setPositions] = useState({});
    const [routes, setRoutes] = useState({});
    const [selectedRoute, setSelectedRoute] = useState(null);
    const [selectedBus, setSelectedBus] = useState(null);

    useEffect(() => {
        const fetchBuses = () => {
            axios.get("http://127.0.0.1:8000/buses")
                .then(res => {
                    setBuses(res.data.buses);
                    setCounts({
                        running_count: res.data.running_count,
                        ghost_count: res.data.ghost_count
                    });
                    setRoutes(res.data.routes);

                    setPositions(prev => {
                        const updated = { ...prev };
                        res.data.buses.forEach(bus => {
                            const oldPos = updated[bus.id] || { currentLat: bus.lat, currentLon: bus.lon };
                            updated[bus.id] = {
                                ...oldPos,
                                targetLat: bus.lat,
                                targetLon: bus.lon,
                                bearing: calculateBearing(oldPos.currentLat, oldPos.currentLon, bus.lat, bus.lon)
                            };
                        });
                        return updated;
                    });
                })
                .catch(err => console.error(err));
        };
        fetchBuses();
        const interval = setInterval(fetchBuses, 1000);
        return () => clearInterval(interval);
    }, []);

    useEffect(() => {
        const anim = setInterval(() => {
            setPositions(prev => {
                const updated = { ...prev };
                Object.keys(updated).forEach(id => {
                    const bus = updated[id];
                    bus.currentLat += (bus.targetLat - bus.currentLat) * 0.1;
                    bus.currentLon += (bus.targetLon - bus.currentLon) * 0.1;
                });
                return updated;
            });
        }, 50);
        return () => clearInterval(anim);
    }, []);

    return (
        <div style={{ position: "relative", height: "100vh" }}>
            <MapContainer center={[19.0760, 72.8777]} zoom={12} style={{ height: "100%", width: "100%" }}>
                <TileLayer
                    url="https://cartodb-basemaps-a.global.ssl.fastly.net/light_all/{z}/{x}/{y}{r}.png"
                    attribution='&copy; <a href="https://www.openstreetmap.org/">OpenStreetMap</a> &copy; CARTO'
                />

                {selectedRoute && routes[selectedRoute] && (
                    <Polyline positions={routes[selectedRoute]} color="blue" />
                )}

                {buses.map(bus => {
                    const pos = positions[bus.id] || { currentLat: bus.lat, currentLon: bus.lon, bearing: 0 };
                    return (
                        <Marker
                            key={bus.id}
                            position={[pos.currentLat, pos.currentLon]}
                            icon={BusIcon({ status: bus.status, bearing: pos.bearing })}
                            eventHandlers={{
                                click: () => {
                                    setSelectedBus(bus);
                                },
                            }}
                        >
                            <Tooltip>Bus ID: {bus.id}</Tooltip>
                        </Marker>
                    );
                })}
            </MapContainer>

            <div style={{ position: "absolute", top: "10px", left: "10px", zIndex: 1000, background: "white", padding: "10px", borderRadius: "5px" }}>
                <select onChange={(e) => setSelectedRoute(e.target.value)} value={selectedRoute || ""}>
                    <option value="" disabled>Select a route to display</option>
                    {Object.keys(routes).map(routeName => (
                        <option key={routeName} value={routeName}>{routeName}</option>
                    ))}
                </select>
            </div>
            
            <BusInfoPanel bus={selectedBus} onClose={() => setSelectedBus(null)} />

            <div style={{
                position: "absolute",
                bottom: "20px",
                left: "10px",
                zIndex: 1000,
                background: "white",
                padding: "5px 10px",
                borderRadius: "5px",
                border: "1px solid #ccc",
                boxShadow: "0 1px 5px rgba(0,0,0,0.4)"
            }}>
                🟢 Running: {counts.running_count} 🔴 Ghost: {counts.ghost_count}
            </div>
        </div>
    );
}
